
const DEFAULT_LOGO_DATA_URL = "data:image/png;base64,";
const STORAGE_KEY = 'skye_pdf_forge_state_v1';
const SNAPSHOT_KEY = 'skye_pdf_forge_snapshots_v1';
const SAMPLE_TEXT = "# Founder Authority Brief\n\nNOTE: This draft was generated inside SkyePDF Forge. Paste raw copy in, keep moving, and let the engine do the pretty part.\n\n## Executive Positioning\n\nSkyes Over London is operating a branded document lane built for turning dense text into polished deliverables without rebuilding the wheel every single time.\n\nThe goal is simple: drop in the words, preserve the brand, export the PDF, and stop babysitting layout goblins.\n\n## Core Utility\n\n- Turn pasted text into a branded multi-page PDF.\n- Keep a cover page, watermark, page numbers, and document headers.\n- Save reusable document states into the local vault.\n- Export the current state as JSON for reuse or import later.\n\n## Example Metrics\n\nSPEED: Raw copy to branded draft in minutes\nFORMAT: A4 or Letter\nEXPORT: PDF + JSON state\nINTRO: Branded cinematic entry layer\n\n## Delivery Notes\n\nCALLOUT: Use short headings, double line breaks, and clean bullets for the best looking export.\n\n[PAGEBREAK]\n\n# Second Page Marker\n\nThis forced page break shows how you can deliberately segment a longer report.\n\n## Suggested Paste Pattern\n\n- Use # for large sections.\n- Use ## for sub-sections.\n- Use NOTE: or CALLOUT: for important callouts.\n- Use [PAGEBREAK] when you want a hard page transition.\n";

const defaultState = {
  docTitle: 'Executive Authority Report',
  docSubtitle: 'Branded PDF export lane for Skyes Over London',
  docType: 'Branded Report',
  preparedFor: 'Internal / Client / Operator',
  preparedBy: 'Skyes Over London',
  pageSize: 'A4',
  showCover: true,
  showWatermark: true,
  showPageNumbers: true,
  brandName: 'Skyes Over London LC',
  brandTagline: 'The Creative Environment Eco-System',
  footerLeft: 'SkyesOverLondonLC@solenterprises.org · SOLEnterprises.org',
  footerRight: 'Branded PDF Generator',
  accentGold: '#ffd36a',
  accentPurple: '#a243ff',
  accentCyan: '#27f2ff',
  watermarkOpacity: 7,
  logoDataUrl: DEFAULT_LOGO_DATA_URL,
  sourceText: ''
};

let state = loadState();
let toastTimer = null;
let introTimer = null;

const els = {
  introOverlay: document.getElementById('introOverlay'),
  skipIntroBtn: document.getElementById('skipIntroBtn'),
  brandLogo: document.getElementById('brandLogo'),
  introLogo: document.getElementById('introLogo'),
  docTitle: document.getElementById('docTitle'),
  docSubtitle: document.getElementById('docSubtitle'),
  docType: document.getElementById('docType'),
  preparedFor: document.getElementById('preparedFor'),
  preparedBy: document.getElementById('preparedBy'),
  pageSize: document.getElementById('pageSize'),
  showCover: document.getElementById('showCover'),
  showWatermark: document.getElementById('showWatermark'),
  showPageNumbers: document.getElementById('showPageNumbers'),
  brandName: document.getElementById('brandName'),
  brandTagline: document.getElementById('brandTagline'),
  footerLeft: document.getElementById('footerLeft'),
  footerRight: document.getElementById('footerRight'),
  accentGold: document.getElementById('accentGold'),
  accentPurple: document.getElementById('accentPurple'),
  accentCyan: document.getElementById('accentCyan'),
  watermarkOpacity: document.getElementById('watermarkOpacity'),
  sourceText: document.getElementById('sourceText'),
  sampleBtn: document.getElementById('sampleBtn'),
  refreshPreviewBtn: document.getElementById('refreshPreviewBtn'),
  clearDocBtn: document.getElementById('clearDocBtn'),
  exportPdfBtn: document.getElementById('exportPdfBtn'),
  downloadJsonBtn: document.getElementById('downloadJsonBtn'),
  importJsonBtn: document.getElementById('importJsonBtn'),
  jsonImportInput: document.getElementById('jsonImportInput'),
  uploadLogoBtn: document.getElementById('uploadLogoBtn'),
  resetLogoBtn: document.getElementById('resetLogoBtn'),
  logoUploadInput: document.getElementById('logoUploadInput'),
  pdfCapture: document.getElementById('pdfCapture'),
  statusLabel: document.getElementById('statusLabel'),
  pageCountLabel: document.getElementById('pageCountLabel'),
  wordCountLabel: document.getElementById('wordCountLabel'),
  saveSnapshotBtn: document.getElementById('saveSnapshotBtn'),
  wipeVaultBtn: document.getElementById('wipeVaultBtn'),
  snapshotList: document.getElementById('snapshotList'),
  printBtn: document.getElementById('printBtn'),
  cloneBtn: document.getElementById('cloneBtn'),
  toast: document.getElementById('toast')
};

const fieldIds = [
  'docTitle','docSubtitle','docType','preparedFor','preparedBy','pageSize',
  'showCover','showWatermark','showPageNumbers','brandName','brandTagline',
  'footerLeft','footerRight','accentGold','accentPurple','accentCyan','watermarkOpacity','sourceText'
];

bindForm();
applyStateToForm();
applyLogo();
applyTheme();
setPageSizeVars();
renderPreview();
renderSnapshots();
startIntro();

function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return { ...defaultState };
    const parsed = JSON.parse(raw);
    return { ...defaultState, ...parsed };
  } catch (err) {
    console.warn(err);
    return { ...defaultState };
  }
}

function saveState() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

function bindForm() {
  fieldIds.forEach((id) => {
    const el = els[id];
    if (!el) return;
    const eventName = el.type === 'checkbox' || el.tagName === 'SELECT' || el.type === 'range' || el.type === 'color' ? 'input' : 'input';
    el.addEventListener(eventName, () => {
      state[id] = el.type === 'checkbox' ? el.checked : el.value;
      applyTheme();
      setPageSizeVars();
      saveState();
      renderPreview();
    });
  });

  els.sampleBtn.addEventListener('click', () => {
    state.sourceText = SAMPLE_TEXT;
    if (!state.docTitle.trim()) state.docTitle = 'Founder Authority Brief';
    if (!state.docSubtitle.trim()) state.docSubtitle = 'Sample export loaded into the forge';
    applyStateToForm();
    saveState();
    renderPreview();
    showToast('Sample document loaded into the forge.');
  });

  els.refreshPreviewBtn.addEventListener('click', () => {
    syncStateFromForm();
    saveState();
    renderPreview();
    showToast('Preview refreshed.');
  });

  els.clearDocBtn.addEventListener('click', () => {
    if (!confirm('Clear the current document state?')) return;
    state = { ...defaultState, sourceText: '', logoDataUrl: state.logoDataUrl || DEFAULT_LOGO_DATA_URL };
    applyStateToForm();
    applyLogo();
    applyTheme();
    setPageSizeVars();
    saveState();
    renderPreview();
    showToast('Current document cleared.');
  });

  els.exportPdfBtn.addEventListener('click', exportPdf);
  els.printBtn.addEventListener('click', () => window.print());

  els.downloadJsonBtn.addEventListener('click', () => {
    syncStateFromForm();
    downloadBlob(JSON.stringify(state, null, 2), `${slugify(state.docTitle || 'skye-pdf-forge')}.json`, 'application/json');
    showToast('JSON state exported.');
  });

  els.importJsonBtn.addEventListener('click', () => els.jsonImportInput.click());
  els.jsonImportInput.addEventListener('change', handleJsonImport);

  els.uploadLogoBtn.addEventListener('click', () => els.logoUploadInput.click());
  els.logoUploadInput.addEventListener('change', handleLogoUpload);
  els.resetLogoBtn.addEventListener('click', () => {
    state.logoDataUrl = DEFAULT_LOGO_DATA_URL;
    applyLogo();
    saveState();
    renderPreview();
    showToast('Logo reset to the default brand mark.');
  });

  els.saveSnapshotBtn.addEventListener('click', saveSnapshot);
  els.wipeVaultBtn.addEventListener('click', wipeSnapshots);
  els.cloneBtn.addEventListener('click', () => {
    state.docTitle = state.docTitle ? `${state.docTitle} Copy` : 'SkyePDF Forge Copy';
    applyStateToForm();
    saveState();
    renderPreview();
    showToast('State duplicated. Rename it and keep moving.');
  });

  els.skipIntroBtn.addEventListener('click', closeIntro);
}

function applyStateToForm() {
  fieldIds.forEach((id) => {
    const el = els[id];
    if (!el) return;
    if (el.type === 'checkbox') el.checked = Boolean(state[id]);
    else el.value = state[id] ?? '';
  });
}

function syncStateFromForm() {
  fieldIds.forEach((id) => {
    const el = els[id];
    if (!el) return;
    state[id] = el.type === 'checkbox' ? el.checked : el.value;
  });
}

function applyLogo() {
  const src = state.logoDataUrl || DEFAULT_LOGO_DATA_URL;
  els.brandLogo.src = src;
  els.introLogo.src = src;
}

function applyTheme() {
  document.documentElement.style.setProperty('--gold', state.accentGold || defaultState.accentGold);
  document.documentElement.style.setProperty('--purple', state.accentPurple || defaultState.accentPurple);
  document.documentElement.style.setProperty('--cyan', state.accentCyan || defaultState.accentCyan);
}

function setPageSizeVars() {
  const root = document.documentElement;
  if (state.pageSize === 'LETTER') {
    root.style.setProperty('--page-w', '816px');
    root.style.setProperty('--page-h', '1056px');
    root.style.setProperty('--page-body-h', '770px');
  } else {
    root.style.setProperty('--page-w', '794px');
    root.style.setProperty('--page-h', '1123px');
    root.style.setProperty('--page-body-h', '840px');
  }
}

function startIntro() {
  introTimer = window.setTimeout(closeIntro, 3200);
}

function closeIntro() {
  window.clearTimeout(introTimer);
  els.introOverlay.classList.add('hidden');
}

function showToast(message) {
  els.toast.textContent = message;
  els.toast.classList.add('show');
  window.clearTimeout(toastTimer);
  toastTimer = window.setTimeout(() => els.toast.classList.remove('show'), 2200);
}

function renderPreview() {
  syncStateFromForm();
  applyLogo();
  applyTheme();
  setPageSizeVars();

  const blocks = parseBlocks(state.sourceText || '');
  const wordCount = ((state.sourceText || '').trim().match(/\S+/g) || []).length;
  els.wordCountLabel.textContent = `${wordCount} words`;

  if (!blocks.length && !state.docTitle.trim() && !state.docSubtitle.trim()) {
    els.pdfCapture.innerHTML = `<div class="empty-state"><div><h3>Nothing in the forge yet.</h3><p>Paste your raw text blob on the left and the branded preview will assemble itself here.</p></div></div>`;
    els.pageCountLabel.textContent = '0 pages';
    els.statusLabel.textContent = 'Waiting';
    return;
  }

  const pages = [];
  els.pdfCapture.innerHTML = '';

  if (state.showCover) {
    const cover = buildCoverPage();
    pages.push(cover);
    els.pdfCapture.appendChild(cover.page);
  }

  let current = buildContentPage();
  pages.push(current);
  els.pdfCapture.appendChild(current.page);

  for (const block of blocks) {
    if (block.kind === 'pagebreak') {
      current = buildContentPage();
      pages.push(current);
      els.pdfCapture.appendChild(current.page);
      continue;
    }
    placeBlock(block, current, pages);
    current = pages[pages.length - 1];
  }

  updatePageNumbers(pages);
  els.pageCountLabel.textContent = `${pages.length} page${pages.length === 1 ? '' : 's'}`;
  els.statusLabel.textContent = 'Previewed';
  saveState();
}

function buildCoverPage() {
  const page = document.createElement('section');
  page.className = 'pdf-page cover-page';
  page.innerHTML = `
    <div class="page-watermark" style="opacity:${state.showWatermark ? Number(state.watermarkOpacity) / 100 : 0}"><img src="${state.logoDataUrl || DEFAULT_LOGO_DATA_URL}" alt="" /></div>
    <div class="page-inner">
      <div>
        <div class="panel-kicker">${escapeHtml(state.brandName || defaultState.brandName)}</div>
        <div class="cover-hero">
          <div>
            <img class="cover-logo" src="${state.logoDataUrl || DEFAULT_LOGO_DATA_URL}" alt="Brand logo" />
            <h1 class="cover-title">${escapeHtml(state.docTitle || 'Untitled Document')}</h1>
            <p class="cover-subtitle">${escapeHtml(state.docSubtitle || state.brandTagline || defaultState.brandTagline)}</p>
          </div>
        </div>
      </div>
      <div class="cover-meta">
        <div class="meta-card"><span class="meta-label">Document Type</span>${escapeHtml(state.docType || 'Branded Report')}</div>
        <div class="meta-card"><span class="meta-label">Prepared For</span>${escapeHtml(state.preparedFor || '—')}</div>
        <div class="meta-card"><span class="meta-label">Prepared By</span>${escapeHtml(state.preparedBy || '—')}</div>
        <div class="meta-card"><span class="meta-label">Issued</span>${escapeHtml(formatDate(new Date()))}</div>
      </div>
    </div>`;
  return { page, body: null, footer: null };
}

function buildContentPage() {
  const page = document.createElement('section');
  page.className = 'pdf-page';
  page.innerHTML = `
    <div class="page-watermark" style="opacity:${state.showWatermark ? Number(state.watermarkOpacity) / 100 : 0}"><img src="${state.logoDataUrl || DEFAULT_LOGO_DATA_URL}" alt="" /></div>
    <div class="page-inner">
      <header class="page-header">
        <div class="page-header-left">
          <img class="page-mini-logo" src="${state.logoDataUrl || DEFAULT_LOGO_DATA_URL}" alt="Brand logo" />
          <div>
            <div class="panel-kicker">${escapeHtml(state.brandName || defaultState.brandName)}</div>
            <div class="page-brand">${escapeHtml(state.docTitle || 'Untitled Document')}</div>
          </div>
        </div>
        <div class="page-doc-type">${escapeHtml(state.docType || 'Branded Report')}</div>
      </header>
      <div class="page-body"></div>
      <footer class="page-footer">
        <div>${escapeHtml(state.footerLeft || '')}</div>
        <div>${escapeHtml(state.footerRight || '')}</div>
        <div class="page-number-slot"></div>
      </footer>
    </div>`;
  return {
    page,
    body: page.querySelector('.page-body'),
    footer: page.querySelector('.page-number-slot')
  };
}

function placeBlock(block, currentPage, pages) {
  const element = createBlockElement(block);
  currentPage.body.appendChild(element);
  if (!isOverflowing(currentPage.body)) return;

  currentPage.body.removeChild(element);
  let next = buildContentPage();
  pages.push(next);
  els.pdfCapture.appendChild(next.page);

  if (block.kind === 'paragraph' && block.text.length > 850) {
    const chunks = splitLongText(block.text, 720);
    for (const chunk of chunks) {
      placeBlock({ ...block, text: chunk }, next, pages);
      next = pages[pages.length - 1];
    }
    return;
  }

  if (block.kind === 'list' && block.items.length > 1) {
    for (const item of block.items) {
      placeBlock({ kind: 'list', items: [item] }, next, pages);
      next = pages[pages.length - 1];
    }
    return;
  }

  next.body.appendChild(element);
}

function createBlockElement(block) {
  if (block.kind === 'heading') {
    const h = document.createElement('h2');
    h.className = 'doc-heading';
    h.textContent = block.text;
    return h;
  }
  if (block.kind === 'subheading') {
    const h = document.createElement('h3');
    h.className = 'doc-subheading';
    h.textContent = block.text;
    return h;
  }
  if (block.kind === 'list') {
    const ul = document.createElement('ul');
    ul.className = 'doc-list';
    block.items.forEach((item) => {
      const li = document.createElement('li');
      li.textContent = item;
      ul.appendChild(li);
    });
    return ul;
  }
  if (block.kind === 'callout') {
    const box = document.createElement('div');
    box.className = 'doc-callout';
    const label = document.createElement('strong');
    label.textContent = block.label || 'Callout';
    const body = document.createElement('div');
    body.className = 'doc-paragraph';
    body.style.margin = '0';
    body.textContent = block.text;
    box.append(label, body);
    return box;
  }
  if (block.kind === 'metrics') {
    const grid = document.createElement('div');
    grid.className = 'doc-metric-grid';
    block.items.forEach((item) => {
      const card = document.createElement('div');
      card.className = 'doc-metric';
      card.innerHTML = `<span class="metric-key">${escapeHtml(item.key)}</span><span class="metric-value">${escapeHtml(item.value)}</span>`;
      grid.appendChild(card);
    });
    return grid;
  }
  if (block.kind === 'divider') {
    const hr = document.createElement('hr');
    hr.className = 'doc-divider';
    return hr;
  }
  const p = document.createElement('p');
  p.className = 'doc-paragraph';
  p.textContent = block.text;
  return p;
}

function parseBlocks(rawText) {
  const text = String(rawText || '').replace(/\r/g, '').trim();
  if (!text) return [];
  const rawBlocks = text.split(/\n{2,}/).map((block) => block.trim()).filter(Boolean);
  const blocks = [];

  rawBlocks.forEach((block) => {
    if (block === '[PAGEBREAK]') {
      blocks.push({ kind: 'pagebreak' });
      return;
    }
    if (/^(---|___)$/.test(block)) {
      blocks.push({ kind: 'divider' });
      return;
    }
    if (block.startsWith('# ')) {
      blocks.push({ kind: 'heading', text: block.slice(2).trim() });
      return;
    }
    if (block.startsWith('## ')) {
      blocks.push({ kind: 'subheading', text: block.slice(3).trim() });
      return;
    }
    if (block.startsWith('### ')) {
      blocks.push({ kind: 'subheading', text: block.slice(4).trim() });
      return;
    }
    if (/^(NOTE|CALLOUT):/i.test(block)) {
      const [, label, rest] = block.match(/^(NOTE|CALLOUT):\s*([\s\S]*)$/i) || [];
      blocks.push({ kind: 'callout', label: label || 'Callout', text: (rest || '').trim() });
      return;
    }

    const lines = block.split('\n').map((line) => line.trim()).filter(Boolean);
    if (lines.length && lines.every((line) => /^[-*]\s+/.test(line))) {
      blocks.push({ kind: 'list', items: lines.map((line) => line.replace(/^[-*]\s+/, '').trim()) });
      return;
    }
    if (lines.length >= 2 && lines.length <= 4 && lines.every((line) => /^[A-Za-z0-9 &/().,'%-]+:\s+.+$/.test(line))) {
      blocks.push({ kind: 'metrics', items: lines.map((line) => {
        const idx = line.indexOf(':');
        return { key: line.slice(0, idx).trim(), value: line.slice(idx + 1).trim() };
      }) });
      return;
    }
    if (block.length <= 90 && /^[A-Z0-9][A-Za-z0-9 '&/().,-]+$/.test(block) && !/[.!?]$/.test(block)) {
      blocks.push({ kind: 'heading', text: block });
      return;
    }

    blocks.push({ kind: 'paragraph', text: block.replace(/\n+/g, ' ').trim() });
  });

  return blocks;
}

function splitLongText(text, maxLength) {
  const sentences = text.split(/(?<=[.!?])\s+/);
  const chunks = [];
  let current = '';
  for (const sentence of sentences) {
    if (!current) {
      current = sentence;
      continue;
    }
    if ((current + ' ' + sentence).length <= maxLength) current += ' ' + sentence;
    else {
      chunks.push(current);
      current = sentence;
    }
  }
  if (current) chunks.push(current);
  return chunks.length ? chunks : [text];
}

function isOverflowing(node) {
  return node.scrollHeight > node.clientHeight + 4;
}

function updatePageNumbers(pages) {
  const total = pages.length;
  pages.forEach((pageObj, index) => {
    if (!pageObj.footer) return;
    pageObj.footer.textContent = state.showPageNumbers ? `Page ${index + 1} of ${total}` : '';
  });
}

async function exportPdf() {
  syncStateFromForm();
  renderPreview();

  if (typeof html2pdf === 'undefined') {
    showToast('PDF library is unavailable right now.');
    return;
  }

  const filename = `${slugify(state.docTitle || 'skye-pdf-forge')}.pdf`;
  els.statusLabel.textContent = 'Exporting';
  showToast('Forging PDF...');

  const worker = html2pdf().set({
    margin: 0,
    filename,
    image: { type: 'jpeg', quality: 0.98 },
    html2canvas: { scale: 2, backgroundColor: '#080a15', useCORS: true, scrollY: 0 },
    jsPDF: { unit: 'pt', format: state.pageSize === 'LETTER' ? 'letter' : 'a4', orientation: 'portrait' },
    pagebreak: { mode: ['css', 'legacy'] }
  }).from(els.pdfCapture);

  try {
    await worker.save();
    els.statusLabel.textContent = 'Exported';
    showToast(`PDF exported: ${filename}`);
  } catch (err) {
    console.error(err);
    els.statusLabel.textContent = 'Error';
    showToast('PDF export failed. Check the browser console.');
  }
}

function handleLogoUpload(event) {
  const file = event.target.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    state.logoDataUrl = reader.result;
    applyLogo();
    saveState();
    renderPreview();
    showToast('Custom logo loaded into the forge.');
  };
  reader.readAsDataURL(file);
  event.target.value = '';
}

function handleJsonImport(event) {
  const file = event.target.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const parsed = JSON.parse(String(reader.result));
      state = { ...defaultState, ...parsed, logoDataUrl: parsed.logoDataUrl || DEFAULT_LOGO_DATA_URL };
      applyStateToForm();
      applyLogo();
      applyTheme();
      setPageSizeVars();
      saveState();
      renderPreview();
      showToast('JSON state imported.');
    } catch (err) {
      console.error(err);
      showToast('That JSON could not be imported.');
    }
  };
  reader.readAsText(file);
  event.target.value = '';
}

function saveSnapshot() {
  syncStateFromForm();
  const name = prompt('Name this snapshot:', state.docTitle || 'Skye PDF Snapshot');
  if (!name) return;
  const snapshots = loadSnapshots();
  snapshots.unshift({
    id: crypto.randomUUID ? crypto.randomUUID() : String(Date.now()),
    name,
    savedAt: new Date().toISOString(),
    state: { ...state }
  });
  localStorage.setItem(SNAPSHOT_KEY, JSON.stringify(snapshots.slice(0, 20)));
  renderSnapshots();
  showToast('Snapshot saved to the vault.');
}

function loadSnapshots() {
  try {
    return JSON.parse(localStorage.getItem(SNAPSHOT_KEY) || '[]');
  } catch (err) {
    console.warn(err);
    return [];
  }
}

function renderSnapshots() {
  const snapshots = loadSnapshots();
  if (!snapshots.length) {
    els.snapshotList.innerHTML = '<div class="microcopy">No saved snapshots yet.</div>';
    return;
  }
  els.snapshotList.innerHTML = '';
  snapshots.forEach((snap) => {
    const card = document.createElement('div');
    card.className = 'snapshot-card';
    card.innerHTML = `
      <div>
        <h4>${escapeHtml(snap.name)}</h4>
        <p>${escapeHtml(formatDate(new Date(snap.savedAt)))}</p>
      </div>
      <div class="action-row">
        <button class="ghost-btn" type="button" data-load="${snap.id}">Load</button>
        <button class="ghost-btn" type="button" data-delete="${snap.id}">Delete</button>
      </div>`;
    els.snapshotList.appendChild(card);
  });
  els.snapshotList.querySelectorAll('[data-load]').forEach((btn) => btn.addEventListener('click', () => loadSnapshot(btn.dataset.load)));
  els.snapshotList.querySelectorAll('[data-delete]').forEach((btn) => btn.addEventListener('click', () => deleteSnapshot(btn.dataset.delete)));
}

function loadSnapshot(id) {
  const snap = loadSnapshots().find((item) => item.id === id);
  if (!snap) return;
  state = { ...defaultState, ...snap.state, logoDataUrl: snap.state.logoDataUrl || DEFAULT_LOGO_DATA_URL };
  applyStateToForm();
  applyLogo();
  applyTheme();
  setPageSizeVars();
  saveState();
  renderPreview();
  showToast(`Loaded snapshot: ${snap.name}`);
}

function deleteSnapshot(id) {
  const snapshots = loadSnapshots().filter((item) => item.id !== id);
  localStorage.setItem(SNAPSHOT_KEY, JSON.stringify(snapshots));
  renderSnapshots();
  showToast('Snapshot deleted.');
}

function wipeSnapshots() {
  if (!confirm('Wipe every saved snapshot in the vault?')) return;
  localStorage.removeItem(SNAPSHOT_KEY);
  renderSnapshots();
  showToast('Vault wiped clean.');
}

function downloadBlob(content, filename, mime) {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

function escapeHtml(value) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}

function slugify(value) {
  return String(value || 'document')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'document';
}

function formatDate(date) {
  return new Intl.DateTimeFormat(undefined, { year: 'numeric', month: 'long', day: 'numeric' }).format(date);
}


if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('./sw.js').catch((err) => console.warn('service worker registration failed', err));
  });
}
